import{_ as l}from"./nyalra_kb-7135827b.js";import{_ as s}from"./nyalra_no_mono-8344e451.js";import{_ as c,W as p,X as _,Y as i,Z as e,$ as t,a1 as o,a2 as m,a0 as u,C as n}from"./framework-91490e6a.js";const d={},f=e("figure",null,[e("img",{src:l,alt:"",tabindex:"0",loading:"lazy"}),e("figcaption")],-1),h={href:"https://tree-novel.com/works/episode/303a98ad4eae31614519739790936c7f.html",target:"_blank",rel:"noopener noreferrer"},k=e("p",null,"这是在互联网中栖息的不可思议生物·Nyalra于深夜写下的有关互联网、独居生活以及除此之外的事物的图文随笔。",-1),g=u('<hr><p>我是通过像这样写文章来赚钱的人，为什么在这个图片与视频的时代之中选择了文字呢？因为这是我唯一能做的。因为这是只需要一部智能手机，任何人都可以参与的类型。如果只是想参与的话，门槛非常低。如果你能够在Twitter上嘀咕日常琐事的话，那么只需要将内容扩展一下就可以完成。因此，尽管它很有深度，但作为工具的话，只需要一部智能手机就足够了。不需要看起来很昂贵的工具或周边机器！「想要写更多好文章！」的写作欲望觉醒时，也无需特意为什么花钱！方便极了！</p><p>甚至只需要纸和笔，连智能手机都可以不用。多么低的要求啊。如果使用电脑编写文字，使用免费的文本编辑器，或者自带的记事本应用也没有问题。我是在智能手机的默认备忘录上写我的每日随笔的。现在已经是每个人都拥有智能手机的时代了，所以任何人在想到「啊，我想要传达点什么！」的时候都可以立即行动。太棒了。值得庆幸的是，由于这个国家的识字率非常高，所以在生活中自然而然地就能掌握写文章的最基本技能。尽管绘画和音乐完全无法达到「能够向他人展示」的水平...</p><p>高中毕业后，在东京无所事事贫穷地独居的时期（虽然也有合租和合居的时候），就在像现在这样写这篇文章时一样孤独的深夜，我突然想到：</p><p><strong>「我想尝试一些创作活动...我希望有人能发现我的存在...」</strong></p><p>事实上，我一事无成，本来就是一个落后的辍学者，因而没有任何绘画或音乐的天赋，也没有努力从头学习的意愿。那么该怎么办呢？说起来，我有智能手机，所以可以写博客。只是像这样通过排除法选择了自己能做到的事情而已。在此之前，并没有任何能够表明我擅长写作的事实。只是相比于绘画和音乐，文字还算能勉强应付。即使现在，我也不能说拥有很好的写作能力。或许我太过随和了。</p><p>**虽然有点离题，但是每当我看到年轻人在互联网上用长文表达对我制作的游戏的感想和思考时，我都感到惊讶：多么伟大啊...**我在学生时代时从未上传过对喜欢的作品或创作者的应援。把对喜欢的作品的热爱转化为语言的冲动是多么珍贵啊，真是让人感动得泪流满面。从根本上说，创作能力也是从这种感受之中成长起来的。这是个好时代啊。而我只是充满了对社会和人类的厌恶和负面情绪。不管怎么说，只要有思绪，只需要在键盘上敲击几下就能立即实行的活动，性价比是最高的。随着媒体的发展，它可能会逐渐缩小，但作为一种用于沟通的文化，文字它永远不会消失。</p><p>正好适合深夜的自我宣泄。因为是把自己的想法和喜欢的事物用语言表达出来的工作，所以可以以自己作为交流对象。能够缓解夜晚的寂寞，还能有一种自己在做有意义的事情的感觉！我至今仍然认为这是逃避现实的最好方法。</p><p>「逃亡路上无天堂」，这是『剑风传奇（ベルセルク）』中的格斯（ガッツ）说的。但像我这样的懦夫即使努力，也只会看到地狱。所以，全力以赴地朝着逃跑的方向奔跑会更好吧。</p><hr><p><img src="'+s+'" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/15fabc7c0dbb7e6296c4f0ec5c3721e0.JPG" alt="" loading="lazy"></p><blockquote><p>本周的にゃるら的物品：</p><p>【Turn A、Turn X＆蝴蝶标本】偶然在Turn A Gundam和Turn X的下方摆放了乌鸦凤蝶和莫鲁凤蝶的标本，感觉非常好，我很高兴。我非常期待Turn A和Turn X的METAL BUILD，如果万代的相关人员读到了这篇专栏的话，请立即提出企划。</p></blockquote>',12);function b(T,x){const a=n("ExternalLinkIcon"),r=n("RouterLink");return p(),_("div",null,[i(" more "),f,e("p",null,[t("原文链接："),e("a",h,[t("第10回／最も準備が楽な創作活動としての文章執筆"),o(a)])]),e("blockquote",null,[k,e("p",null,[o(r,{to:"/posts/Translate/nyalra_kb_09.html"},{default:m(()=>[t("【奈亚拉面壁自语】第09回｜养蜘蛛【230117】")]),_:1})])]),g])}const v=c(d,[["render",b],["__file","nyalra_kb_10.html.vue"]]);export{v as default};
